#!/usr/bin/env python3

from PIL import Image
import sys

def get_average_color(image, x_start, y_start, width, height):
    """Get average color of a region in the image"""
    total_r = total_g = total_b = 0
    count = 0

    for y in range(y_start, y_start + height):
        for x in range(x_start, x_start + width):
            r, g, b = image.getpixel((x, y))
            total_r += r
            total_g += g
            total_b += b
            count += 1

    return (total_r // count, total_g // count, total_b // count)

def is_square_light(row, col):
    """Check if a square is light colored on a chess board"""
    return (row + col) % 2 == 0

def detect_piece(color, is_light_square):
    """Detect what piece is on a square based on color"""
    r, g, b = color

    # Thresholds for determining colors
    brightness = (r + g + b) // 3

    # Empty square (close to board color)
    if brightness > 200:
        return '.'  # Empty square

    # Determine if it's a dark or light piece
    if r > g and r > b:
        return 'R' if is_light_square else 'r'  # Reddish - could be rook
    elif b > r and b > g:
        return 'B' if is_light_square else 'b'  # Blueish - could be bishop
    elif g > r and g > b:
        return 'N' if is_light_square else 'n'  # Greenish - could be knight
    elif r > 150 and g > 150 and b < 100:
        return 'Q' if is_light_square else 'q'  # Yellowish - could be queen
    elif abs(r - g) < 30 and abs(g - b) < 30 and r < 100:
        return 'K' if is_light_square else 'k'  # Dark grayish - could be king
    elif r > 150 and g > 150 and b > 150:
        return 'P' if is_light_square else 'p'  # Light grayish - could be pawn
    else:
        return '?'  # Unknown piece

def analyze_chess_board(image_path):
    """Analyze the chess board image and return FEN notation"""
    img = Image.open(image_path)
    width, height = img.size

    # Assuming 8x8 board
    square_width = width // 8
    square_height = height // 8

    board = [['.' for _ in range(8)] for _ in range(8)]

    for row in range(8):
        for col in range(8):
            x_start = col * square_width
            y_start = row * square_height

            # Get a slightly smaller region to avoid edge artifacts
            margin = square_width // 10
            avg_color = get_average_color(
                img,
                x_start + margin,
                y_start + margin,
                square_width - 2 * margin,
                square_height - 2 * margin
            )

            is_light = is_square_light(row, col)
            piece = detect_piece(avg_color, is_light)
            board[row][col] = piece

    return board

def board_to_fen(board):
    """Convert board representation to FEN notation"""
    fen_rows = []
    for row in board:
        fen_row = ''
        empty_count = 0
        for piece in row:
            if piece == '.':
                empty_count += 1
            else:
                if empty_count > 0:
                    fen_row += str(empty_count)
                    empty_count = 0
                fen_row += piece
        if empty_count > 0:
            fen_row += str(empty_count)
        fen_rows.append(fen_row)
    return '/'.join(fen_rows) + ' w - - 0 1'

def print_board(board):
    """Print the board in a readable format"""
    for i, row in enumerate(board):
        print(f"{8-i} {' '.join(row)}")
    print("  a b c d e f g h")

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python3 analyze_chess.py <image_path>")
        sys.exit(1)

    image_path = sys.argv[1]
    board = analyze_chess_board(image_path)
    print("Detected board position:")
    print_board(board)
    print("\nFEN notation:")
    print(board_to_fen(board))
EOF
